import{_ as t,o as a,c as i,a0 as n}from"./chunks/framework.jwovEGr5.js";const h=JSON.parse('{"title":"Analytics & Premium Gating Tests","description":"","frontmatter":{},"headers":[],"relativePath":"testing/analytics-tests.md","filePath":"testing/analytics-tests.md"}'),s={name:"testing/analytics-tests.md"};function r(l,e,o,c,d,m){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="analytics-premium-gating-tests" tabindex="-1">Analytics &amp; Premium Gating Tests <a class="header-anchor" href="#analytics-premium-gating-tests" aria-label="Permalink to &quot;Analytics &amp; Premium Gating Tests&quot;">​</a></h1><p>Use this guide to confirm locked and unlocked states for premium analytics and the special Kingdom-tab grant rule for alliance leadership.</p><h2 id="test-1-player-cross-event-analytics" tabindex="-1">Test 1. Player cross-event analytics <a class="header-anchor" href="#test-1-player-cross-event-analytics" aria-label="Permalink to &quot;Test 1. Player cross-event analytics&quot;">​</a></h2><ol><li>Sign in as Alliance Leader or Co-Leader without the premium player feature. Expected result: the <strong>Player</strong> tab shows a locked premium prompt.</li><li>Assign a premium plan carrying player cross-event analytics. Expected result: the <strong>Player</strong> tab unlocks.</li><li>Search for a player and open the tab. Expected result: cross-event charts, rankings, and the event breakdown appear.</li><li>Remove the premium plan or the relevant grant. Expected result: the tab returns to the locked state.</li></ol><h2 id="test-2-custom-analytics" tabindex="-1">Test 2. Custom analytics <a class="header-anchor" href="#test-2-custom-analytics" aria-label="Permalink to &quot;Test 2. Custom analytics&quot;">​</a></h2><ol><li>Sign in without the custom analytics feature. Expected result: the <strong>Custom</strong> tab shows a locked premium prompt.</li><li>Assign a premium plan carrying custom analytics. Expected result: the <strong>Custom</strong> tab unlocks.</li><li>Open the tab. Expected result: event filters, date filters, metric and grouping selectors, a trend chart, and the custom table are visible.</li><li>Remove the premium plan or the relevant grant. Expected result: the tab returns to the locked state.</li></ol><h2 id="test-3-recommendations" tabindex="-1">Test 3. Recommendations <a class="header-anchor" href="#test-3-recommendations" aria-label="Permalink to &quot;Test 3. Recommendations&quot;">​</a></h2><ol><li>Sign in without the premium recommendation features. Expected result: the recommendation areas show locked notices instead of the premium follow-up content.</li><li>Assign a premium plan carrying recommendation features. Expected result: the relevant recommendation areas unlock.</li><li>Open alliance analytics. Expected result: watchlists and recommendation-driven follow-up content appear.</li><li>Remove the premium plan or the relevant grant. Expected result: the locked notices return.</li></ol><h2 id="test-4-kingdom-tab-visibility-for-alliance-leader" tabindex="-1">Test 4. Kingdom tab visibility for Alliance Leader <a class="header-anchor" href="#test-4-kingdom-tab-visibility-for-alliance-leader" aria-label="Permalink to &quot;Test 4. Kingdom tab visibility for Alliance Leader&quot;">​</a></h2><ol><li>Sign in as Alliance Leader with no accepted kingdom grant. Expected result: the Kingdom tab is not visible.</li><li>Offer and accept a kingdom grant that includes <code>kingdom_analytics_for_granted_alliances</code>. Expected result: the Kingdom tab appears for that alliance leadership scope.</li><li>Open the Kingdom tab. Expected result: the view opens in the granted aggregate mode rather than full kingdom-admin detail.</li><li>Revoke the grant. Expected result: the Kingdom tab disappears again.</li></ol>',10)])])}const u=t(s,[["render",r]]);export{h as __pageData,u as default};
